const crypto = require('crypto');
const secret = $env.WEBHOOK_SECRET || '';
if (!secret) return [{json: $input.item.json}]; // skip if no secret configured

const sig = $input.item.json.headers?.['x-hub-signature-256'] || '';
const body = JSON.stringify($input.item.json.body);
const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(body).digest('hex');

if (sig !== expected) {
  throw new Error('Invalid webhook signature — request rejected');
}
return [{json: $input.item.json}];

